<section id="schedule" style="background:var(--bg2);">
  <div class="container">
    <div class="sec-head">
      <h2 class="sec-title">
        <div class="sec-title-icon">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect width="18" height="18" x="3" y="4" rx="2" ry="2"/><line x1="16" x2="16" y1="2" y2="6"/><line x1="8" x2="8" y1="2" y2="6"/><line x1="3" x2="21" y1="10" y2="10"/></svg>
        </div>
        Release <span class="accent">Schedule</span>
      </h2>
    </div>
    <div class="day-tabs" id="dayTabs">
      <button class="day-tab active" data-day="Sun">Sun (Today)</button>
      <button class="day-tab" data-day="Mon">Mon</button>
      <button class="day-tab" data-day="Tue">Tue</button>
      <button class="day-tab" data-day="Wed">Wed</button>
      <button class="day-tab" data-day="Thu">Thu</button>
      <button class="day-tab" data-day="Fri">Fri</button>
      <button class="day-tab" data-day="Sat">Sat</button>
    </div>
    <div class="sched-grid" id="schedGrid">
      <div class="sched-card" data-day="Sun" onclick="showToast('Opening Shadow Realm Chronicles...')"><div class="sched-thumb"><img src="https://picsum.photos/seed/vexio-sched-1/160/220" alt="Shadow Realm Chronicles poster" loading="lazy"></div><div><div class="sched-time">12:00 AM</div><div class="sched-title">Shadow Realm Chronicles</div><div class="sched-ep">Ep 25<span class="sched-new">NEW</span></div></div></div>
      <div class="sched-card" data-day="Sun" onclick="showToast('Opening Eternal Blossom Academy...')"><div class="sched-thumb"><img src="https://picsum.photos/seed/vexio-sched-2/160/220" alt="Eternal Blossom Academy poster" loading="lazy"></div><div><div class="sched-time">2:30 AM</div><div class="sched-title">Eternal Blossom Academy</div><div class="sched-ep">Ep 13<span class="sched-new">NEW</span></div></div></div>
      <div class="sched-card" data-day="Mon" hidden onclick="showToast('Opening Iron Wolf Awakening...')"><div class="sched-thumb"><img src="https://picsum.photos/seed/vexio-sched-3/160/220" alt="Iron Wolf Awakening poster" loading="lazy"></div><div><div class="sched-time">1:00 AM</div><div class="sched-title">Iron Wolf Awakening</div><div class="sched-ep">Ep 9<span class="sched-new">NEW</span></div></div></div>
      <div class="sched-card" data-day="Tue" hidden onclick="showToast('Opening Forgotten God Protocol...')"><div class="sched-thumb"><img src="https://picsum.photos/seed/vexio-sched-4/160/220" alt="Forgotten God Protocol poster" loading="lazy"></div><div><div class="sched-time">12:30 AM</div><div class="sched-title">Forgotten God Protocol</div><div class="sched-ep">Ep 17<span class="sched-new">NEW</span></div></div></div>
      <div class="sched-card" data-day="Wed" hidden onclick="showToast('Opening Ten Thousand Swords...')"><div class="sched-thumb"><img src="https://picsum.photos/seed/vexio-sched-5/160/220" alt="Ten Thousand Swords poster" loading="lazy"></div><div><div class="sched-time">2:00 AM</div><div class="sched-title">Ten Thousand Swords</div><div class="sched-ep">Ep 33<span class="sched-new">NEW</span></div></div></div>
      <div class="sched-card" data-day="Thu" hidden onclick="showToast('Opening Crystal Hearts...')"><div class="sched-thumb"><img src="https://picsum.photos/seed/vexio-sched-6/160/220" alt="Crystal Hearts poster" loading="lazy"></div><div><div class="sched-time">1:30 AM</div><div class="sched-title">Crystal Hearts</div><div class="sched-ep">Ep 2<span class="sched-new">NEW</span></div></div></div>
      <div class="sched-card" data-day="Fri" hidden onclick="showToast('Opening Starfall Covenant...')"><div class="sched-thumb"><img src="https://picsum.photos/seed/vexio-sched-7/160/220" alt="Starfall Covenant poster" loading="lazy"></div><div><div class="sched-time">12:00 AM</div><div class="sched-title">Starfall Covenant</div><div class="sched-ep">Ep 11<span class="sched-new">NEW</span></div></div></div>
      <div class="sched-card" data-day="Sat" hidden onclick="showToast('Opening God Throne Tournament...')"><div class="sched-thumb"><img src="https://picsum.photos/seed/vexio-sched-8/160/220" alt="God Throne Tournament poster" loading="lazy"></div><div><div class="sched-time">8:00 PM</div><div class="sched-title">God Throne Tournament</div><div class="sched-ep">Ep 9<span class="sched-new">NEW</span></div></div></div>
    </div>
  </div>
</section>
